import flatpickr from "flatpickr";
import "flatpickr/dist/flatpickr.min.css";
import iziToast from 'izitoast';
import 'izitoast/dist/css/iziToast.min.css';

const startBtn = document.querySelector('[data-start]');
const daysEl = document.querySelector('[data-days]');
const hoursEl = document.querySelector('[data-hours]');
const minutesEl = document.querySelector('[data-minutes]');
const secondsEl = document.querySelector('[data-seconds]');
const inputEl = document.querySelector('#datetime-picker');

let userSelectedData = null;
let timerId = null;

const fp = flatpickr('#datetime-picker', {
    enableTime: true,
    time_24hr: true,
    defaultDate: new Date(),
    minuteIncrement: 1,
    onClose(selectedDates) {
        const chosen = selectedDates[0];

        if (chosen <= new Date()) {
            iziToast.error({
                message: 'Please choose a date in the future',
                position: 'topRight',
            });
            startBtn.disabled = true;
            userSelectedData = null;
            return
        }
        userSelectedData = chosen;
        startBtn.disabled = false;
    },
});

function addLeadingZero(value) {
    return String(value).padStart(2, '0');
}

function convertMs(ms) {
  const second = 1000;
  const minute = second * 60;
  const hour = minute * 60;
  const day = hour * 24;

  const days = Math.floor(ms / day);
  const hours = Math.floor((ms % day) / hour);
  const minutes = Math.floor(((ms % day) % hour) / minute);
  const seconds = Math.floor((((ms % day) % hour) % minute) / second);

  return { days, hours, minutes, seconds };
}

function updateUI({ days, hours, minutes, seconds }) {
    daysEl.textContent = addLeadingZero(days);
    hoursEl.textContent = addLeadingZero(hours);
    minutesEl.textContent = addLeadingZero(minutes);
    secondsEl.textContent = addLeadingZero(seconds);
}

function startTimer(endDate) {
    startBtn.disabled = true;
    inputEl.disabled = true;

    updateUI(convertMs(endDate - Date.now()));

    timerId = setInterval(() => {
        const ms = endDate - Date.now();

        if (ms <= 0) {
            clearInterval(timerId);
            updateUI({ days: 0, hours: 0, minutes: 0, seconds: 0 });
            inputEl.disabled = false;
            fp.set('clickOpens', true);
            return;
        }
        updateUI(convertMs(ms));
    }, 1000);
    }

startBtn.addEventListener('click', () => {
    if (!userSelectedData) return;
    startTimer(userSelectedData);
});


